using UnityEngine;

/// <summary>
/// Zona de vento (Tarefa #6 — Vento): Collider2D (Trigger) que aplica uma
/// força contínua de vento (direcção + intensidade, configuráveis por zona) a
/// tudo o que estiver dentro:
///
/// - Player: PlayerMotor2D.ApplyWind — parado desloca-se (mais quanto mais
///   leve for a forma); a andar a favor do vento ganha velocidade extra
///   (inclui saltos); a andar contra sofre resistência. Vento vertical para
///   cima reduz a gravidade efectiva (sobe/cai mais devagar, salta mais
///   alto/longe); vento para baixo aumenta-a (cai/salta mais rápido e baixo).
///
/// - Objectos soltos (<see cref="Carryable"/>, não carregados) e qualquer
///   GameObject marcado com <see cref="WindAffectable"/> (inimigos, NPCs,
///   decorações com Rigidbody2D dinâmico): força = vento / peso
///   (GameWeightUtil.GetWindWeightOf) — objectos muito leves com vento forte
///   para cima podem "flutuar" (aceleração ascendente supera a gravidade).
///
/// Colocar num GameObject com Collider2D marcado como "Is Trigger" sobre a
/// área afectada (ex.: corredor com correntes de ar, topo de penhasco
/// ventoso, ventoinhas industriais).
/// </summary>
[RequireComponent(typeof(Collider2D))]
public class WindZone : MonoBehaviour
{
    [Header("Vento")]
    [Tooltip("Direcção do vento (normalizada internamente). Ex.: (1,0) = vento para a direita; (0,1) = vento para cima; (0,-1) = vento para baixo.")]
    public Vector2 windDirection = Vector2.right;

    [Tooltip("Intensidade do vento (força aplicada por segundo, antes de dividir pelo peso do alvo).")]
    [Min(0f)] public float windStrength = 6f;

    [Header("Quem é Afectado")]
    [Tooltip("Afecta o player (PlayerMotor2D.ApplyWind).")]
    public bool affectsPlayer = true;

    [Tooltip("Afecta objectos soltos (Carryable não carregados) e GameObjects marcados com WindAffectable (inimigos/NPCs/decorações).")]
    public bool affectsOthers = true;

    [Tooltip("Tarefa #7 — Guepardo: marca esta zona como uma 'corrente pequena/fraca'. Formas com AnimalFormData.canBreakSmallWindCurrents (Guepardo) ignoram-na enquanto SprintAbility.IsSprinting.")]
    public bool isSmallCurrent = false;

    /// <summary>Vento efectivo (direcção normalizada * intensidade) — cacheado por frame de física.</summary>
    private Vector2 EffectiveWind => windDirection.sqrMagnitude > 0.0001f
        ? windDirection.normalized * windStrength
        : Vector2.zero;

    private void OnTriggerStay2D(Collider2D other)
    {
        Vector2 wind = EffectiveWind;
        if (wind == Vector2.zero) return;

        if (other.CompareTag("Player"))
        {
            if (!affectsPlayer) return;

            var motor = other.GetComponent<PlayerMotor2D>();
            if (motor != null) motor.ApplyWind(wind, isSmallCurrent);
            return;
        }

        if (!affectsOthers) return;

        var carryable = other.GetComponent<Carryable>();
        var windAffectable = other.GetComponent<WindAffectable>();

        bool eligible = (carryable != null && !carryable.IsCarried)
                        || (windAffectable != null && windAffectable.affectedByWind);

        if (!eligible) return;

        var rb = other.attachedRigidbody;
        if (rb == null || rb.bodyType != RigidbodyType2D.Dynamic) return;

        float weight = GameWeightUtil.GetWindWeightOf(other);
        rb.AddForce(wind / weight, ForceMode2D.Force);
    }

    private void OnDrawGizmos()
    {
        var col = GetComponent<Collider2D>();
        if (col == null) return;

        Gizmos.color = new Color(0.6f, 0.9f, 1f, 0.3f);
        Gizmos.DrawCube(col.bounds.center, col.bounds.size);

        // Seta indicativa da direcção do vento.
        Gizmos.color = Color.white;
        Vector3 center = col.bounds.center;
        Vector3 dir = ((Vector2)windDirection).normalized;
        if (dir != Vector3.zero)
            Gizmos.DrawLine(center, center + dir * (1f + windStrength * 0.1f));
    }
}
